/* FreeRTOS 任务通信架构：三种范式的接口定义 */

/* 范式 1：共享内存 + 互斥锁（不推荐用于跨模块通信）*/
typedef struct {
    volatile uint32_t temperature;
    volatile uint32_t humidity;
} shared_sensor_data_t;

/* 范式 2：消息队列（推荐用于数据传输）*/
typedef struct {
    uint16_t sensor_id;
    int16_t  temperature_x10;   /* 25.3°C -> 253 */
    uint16_t humidity_x2;       /* 65% -> 130 */
    uint32_t timestamp_ms;
} sensor_msg_t;                /* 12 bytes */

QueueHandle_t xSensorQueue;

/* 范式 3：事件组（推荐用于触发信号）*/
#define BIT_TEMP_READY    (1 << 0)
#define BIT_HUMID_READY   (1 << 1)
#define BIT_ALL_READY     (BIT_TEMP_READY | BIT_HUMID_READY)

EventGroupHandle_t xSensorEvents;

/* 创建接口 */
xSensorQueue = xQueueCreate(10, sizeof(sensor_msg_t));
xSensorEvents = xEventGroupCreate();

/* 生产者：发送数据 */
void producer_task(void *pvParameters) {
    sensor_msg_t msg = { .sensor_id = 1, .temperature_x10 = 253 };
    xQueueSend(xSensorQueue, &msg, pdMS_TO_TICKS(100));
}

/* 消费者：接收数据 */
void consumer_task(void *pvParameters) {
    sensor_msg_t msg;
    if (xQueueReceive(xSensorQueue, &msg, pdMS_TO_TICKS(500)) == pdPASS) {
        /* 处理 msg */
    }
}

#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"

/* 命令结构体：8 字节，适合实时控制 */
typedef struct {
    uint8_t  cmd_id;
    int16_t  value_x100;      /* 放大 100 倍避免浮点 */
    uint32_t timestamp_ms;
} command_t;

#define CMD_QUEUE_DEPTH   16
#define CMD_SEND_TIMEOUT  pdMS_TO_TICKS(100)
#define CMD_RECV_TIMEOUT  pdMS_TO_TICKS(500)

static QueueHandle_t xCmdQueue;
static volatile uint32_t uxOverflowCount = 0;

/* 初始化：创建队列 */
BaseType_t CmdQueue_Init(void) {
    xCmdQueue = xQueueCreate(CMD_QUEUE_DEPTH, sizeof(command_t));
    return (xCmdQueue != NULL) ? pdPASS : pdFAIL;
}

/* 生产者：从采集 ISR 安全发送命令 */
BaseType_t CmdQueue_SendFromISR(command_t *cmd) {
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;
    BaseType_t ret = xQueueSendFromISR(
        xCmdQueue, cmd, &xHigherPriorityTaskWoken);

    if (ret != pdPASS) {
        uxOverflowCount++;  /* 队列满，丢弃并计数 */
        if (uxOverflowCount > 100) {
            /* 溢出过多，触发告警任务提高优先级 */
            vTaskPrioritySet(NULL, tskIDLE_PRIORITY + 3);
        }
    }
    portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    return ret;
}

/* 消费者：处理任务中接收命令 */
void CmdProcessor_Task(void *pvParameters) {
    command_t cmd;
    while (1) {
        if (xQueueReceive(xCmdQueue, &cmd,
                          CMD_RECV_TIMEOUT) == pdPASS) {
            switch (cmd.cmd_id) {
                case CMD_SET_PWM:
                    TIM2->CCR1 = (uint16_t)(cmd.value_x100 / 10);
                    break;
                case CMD_LOG_DATA:
                    Log_Write(cmd.timestamp_ms, cmd.value_x100);
                    break;
                default:
                    /* 未知命令，忽略 */
                    break;
            }
        } else {
            /* 超时：发送心跳或执行周期性维护 */
            Heartbeat_Ping();
        }
    }
}

/* FreeRTOS 任务通信调试辅助：栈溢出检测 + 队列状态监控 */

/* 启用栈溢出检测（FreeRTOSConfig.h）*/
/* #define configCHECK_FOR_STACK_OVERFLOW  2 */

void vApplicationStackOverflowHook(TaskHandle_t xTask, char *pcTaskName) {
    /* 栈溢出时打印任务名，便于定位 */
    printf("[FATAL] Stack overflow in task: %s\r\n", pcTaskName);
    /* 可以在此触发 LED 闪烁或进入调试模式 */
    while(1) { }
}

/* 队列状态监控任务：定期检查队列健康 */
void QueueMonitor_Task(void *pvParameters) {
    while (1) {
        uint32_t queued = uxQueueMessagesWaiting(xCmdQueue);
        uint32_t free = uxQueueSpacesAvailable(xCmdQueue);

        if (queued > CMD_QUEUE_DEPTH * 0.8) {
            printf("[WARN] Queue near full: %lu/%lu\r\n", 
                   queued, CMD_QUEUE_DEPTH);
        }
        if (free == 0 && uxOverflowCount > 0) {
            printf("[ERROR] Queue overflow detected: %lu times\r\n",
                   uxOverflowCount);
            /* 可以在此重置系统或进入安全模式 */
        }

        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

/* 优先级继承验证：确认使用 Mutex 而非 Binary Semaphore */
SemaphoreHandle_t xSharedDataMutex;

void HighPriority_Task(void *pvParameters) {
    /* 正确：使用 Mutex，自动优先级继承 */
    if (xSemaphoreTake(xSharedDataMutex, pdMS_TO_TICKS(100)) == pdPASS) {
        /* 访问共享数据 */
        xSemaphoreGive(xSharedDataMutex);
    }
    /* 错误示例（注释）：
    if (xSemaphoreTake(xBinarySem, ...) == pdPASS) { ... }
    二进制信号量没有优先级继承！*/
}

/* ===== 重构前：轮询等待（坏味道：CPU 空转） ===== */
volatile uint8_t g_flag_ready = 0;

void MainLoop_Task(void *pvParameters) {
    while (1) {
        /* 忙等待：CPU 100% 空转直到传感器完成 */
        while (!g_flag_ready) {
            /* 什么问题都不做，只是浪费电力 */
        }
        g_flag_ready = 0;
        Process_SensorData();
        vTaskDelay(pdMS_TO_TICKS(100));
    }
}

/* ===== 重构后：事件驱动（零等待 + 超时保护） ===== */

#define EVENT_DATA_READY  (1 << 0)
#define EVENT_CALIB_DONE  (1 << 1)
#define EVENT_ERROR       (1 << 2)
#define EVENT_ALL         (EVENT_DATA_READY | EVENT_CALIB_DONE)

static EventGroupHandle_t xSensorEvents;
static QueueHandle_t xDataQueue;

typedef struct {
    int16_t temp_x10;
    uint16_t hum_x2;
    uint32_t ts_ms;
} sensor_reading_t;

void SensorProducer_Task(void *pvParameters) {
    sensor_reading_t reading;
    while (1) {
        Read_Sensors(&reading);          /* 阻塞式读取传感器 */
        xQueueSend(xDataQueue, &reading, pdMS_TO_TICKS(100));
        xEventGroupSetBits(xSensorEvents,
                           EVENT_DATA_READY);
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

void MainLoop_EventDriven_Task(void *pvParameters) {
    sensor_reading_t reading;
    while (1) {
        /* 等待数据就绪，超时 5000ms */
        EventBits_t bits = xEventGroupWaitBits(
            xSensorEvents,
            EVENT_DATA_READY,
            pdTRUE,   /* 自动清除已设置的位 */
            pdFALSE,  /* 等待所有位（OR 语义）*/
            pdMS_TO_TICKS(5000));

        if (bits & EVENT_DATA_READY) {
            /* 有数据可用，从队列取出 */
            if (xQueueReceive(xDataQueue, &reading,
                              pdMS_TO_TICKS(100)) == pdPASS) {
                Control_Update(reading.temp_x10,
                               reading.hum_x2);
            }
        } else {
            /* 超时：传感器可能故障，进入安全模式 */
            Enter_Safe_Mode();
            Log_Error("Sensor timeout");
        }
    }
}
